@celery.task(bind=True, max_retries=5)
def send_email_task(self, email_data):
    # Send transactional email
    mailer = MailerClient()

    if not email_data.get('to'):
        return

    try:
        mailer.send(email_data)
    except Exception as exc:
        print('Mail failed, scheduling retry')
        # PROBLEM: Retrying with a fixed delay of 60s
        # Better to increase delay for subsequent failures to avoid congestion
        # self.retry(exc=exc, countdown=60)
        raise self.retry(exc=exc, countdown=60)
